pipeline.evaluate:
(() => {
  const results = [];
  const seen = new Set();
  const items = document.querySelectorAll('[data-testid^="notification"]');

  items.forEach(item => {
    try {
      const text = item.textContent || '';
      const link = item.querySelector('a[href*="/status/"]');
      const url = link ? link.href : 'https://x.com/notifications';
      const id = url.match(/\/status\/(\d+)/)?.[1] || Math.random().toString();

      if (seen.has(id)) return;
      seen.add(id);

      results.push({
        id,
        action: 'Notification',
        text: text.substring(0, 100),
        url
      });
    } catch (e) {}
  });

  return results;
})()
